queries.sparql:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?engineering_class a :Engineering_Class .
    ?engineering_class p:name ?name .
    ?engineering_class p:Projects ?projects_f .
    FILTER(STR(?projects_f) = "Sustainability Project")
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?design_class a :Design_Class .
    ?design_class p:name ?name .
    ?design_class p:Projects ?projects_f .
    FILTER(STR(?projects_f) = "Sustainability Project")
    BIND(?name AS ?o0)
  }
}

